//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
  ds_results.removeAll();
  ds_clnt.removeAll();
  ds_manager.removeAll();

  //tr_retrieve.post();
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    totalRowsResults.setValue(ds_results.getRowCount());
    if (ds_results.getRowCount() == 0) {
      $c.win.alert($p, "조회된 데이터가 없습니다.");
      //$c.gus.cfAlertMsg(MSG_CM_WRN_002);
      return false;
    } else {
      gr_results.setFocusedCell(0, 0);
      scwin.f_retrieve_clntAndManager();
      $c.gus.cfDisableObjects($p, [ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy, ed_clntNo_rslts, txt_clntNm_rslts, acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2, acb_lux_degClsCd, ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt, ed_txt_insrTrf, ica_em_cutShedDt, em_insrTermFrom, em_insrTermTo, rd_useYn, ed_txt_rmk]);
    }
  }
};
scwin.f_retrieve_clntAndManager = function () {
  dma_cond_clntManager.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));

  //tr_retrieve_clntAndMngnr.post();
  $c.sbm.execute($p, sbm_retrieve_clntAndMngnr);
};
scwin.sbm_retrieve_clntAndMngnr_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    totalRowsClnt.setValue(ds_clnt.getRowCount());
    totalRowsManager.setValue(ds_manager.getRowCount());
    scwin.retrieveDetailYn = "yes";
  }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
  //저장을 무조건 타도록
  ds_results.setCellData(ds_results.getRowPosition(), "modDtm", "1");
  for (var i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getRowStatusValue(i) == "1" || ds_results.getRowStatusValue(i) == "2" || ds_results.getRowStatusValue(i) == "3") {
      if (ds_results.getCellData(i, "vehclNo") == "") {
        $c.win.alert($p, "차량번호는 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_results.getCellData(i, "ton") == "") {
        $c.win.alert($p, "차량번호 " + ds_results.getCellData(i, "vehclNo") + "의 톤은 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_results.getCellData(i, "clntNo") == "") {
        $c.win.alert($p, "차량번호 " + ds_results.getCellData(i, "vehclNo") + "의 소속거래처는 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_results.getCellData(i, "bizTypCd") == "") {
        $c.win.alert($p, "차량번호 " + ds_results.getCellData(i, "vehclNo") + "의 업종코드는 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_results.getCellData(i, "trfAdptCd") == "") {
        $c.win.alert($p, "차량번호 " + ds_results.getCellData(i, "vehclNo") + "의 요율적용코드는 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_results.getCellData(i, "useYn") == 1 && ds_manager.getRowCount() == 0) {
        $c.win.alert($p, "매니저 정보를 입력해야 합니다.");
        return false;
      }
    }
  }
  for (var i = 0; i < ds_clnt.getRowCount(); i++) {
    if (ds_clnt.getRowStatusValue(i) == "1" || ds_clnt.getRowStatusValue(i) == "2" || ds_clnt.getRowStatusValue(i) == "3") {
      if (ds_clnt.getCellData(i, "clntNo") == "") {
        $c.win.alert($p, "매출거래처는 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_clnt.getCellData(i, "ctrtStDt") == "") {
        $c.win.alert($p, "매출거래처의 적용일자FROM은  필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_clnt.getCellData(i, "ctrtEndDt") == "") {
        $c.win.alert($p, "매출거래처의 적용일자TO는  필수 입력 항목 입니다.");
        return false;
        break;
      }
    }
  }
  for (var i = 0; i < ds_manager.getRowCount(); i++) {
    if (ds_manager.getRowStatusValue(i) == "1" || ds_manager.getRowStatusValue(i) == "2" || ds_manager.getRowStatusValue(i) == "3") {
      if (ds_manager.getCellData(i, "clntNo") == "") {
        $c.win.alert($p, "매니저코드는 필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_manager.getCellData(i, "ctrtStDt") == "") {
        $c.win.alert($p, "매니저의 적용일자FROM은  필수 입력 항목 입니다.");
        return false;
        break;
      }
      if (ds_manager.getCellData(i, "ctrtEndDt") == "") {
        $c.win.alert($p, "매니저의 적용일자TO는  필수 입력 항목 입니다.");
        return false;
        break;
      }
    }
  }
  let confirm = await $c.win.confirm($p, MSG_CM_CRM_001); //저장하시겠습니까?
  if (confirm) {
    //tr_save.Post();
    $c.sbm.execute($p, sbm_save);
  }
};
scwin.sbm_save_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다.
    scwin.btn_retrieve_onclick();
  }
};

