scwin.btn_new_onclick = function (e) {
  ds_results.removeAll();
  ds_results.insertRow();
  gr_results.setFocusedCell(0, 0);
  ds_results.setCellData(ds_results.getRowPosition(), "useYn", "1");
  ds_results.setCellData(ds_results.getRowPosition(), "coCd", "022"); //대성TLS 자회사 코드

  ds_clnt.removeAll();
  ds_manager.removeAll();
  $c.gus.cfEnableObjects($p, [ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy, ed_clntNo_rslts, txt_clntNm_rslts, acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2, acb_lux_degClsCd, ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt, ed_txt_insrTrf, ica_em_cutShedDt, em_insrTermFrom, em_insrTermTo, rd_useYn, ed_txt_rmk]);
};

