scwin.gr_clnt_onafteredit = function (rowIndex, columnIndex, value) {
  try {
    let colid = gr_clnt.getColumnID(columnIndex);
    if (colid == "clntNm") {
      let clntNm = ds_clnt.getCellData(rowIndex, "clntNm");
      if (clntNm == "") {
        ds_clnt.setCellData(rowIndex, "clntNm", "");
        return false;
      }
      scwin.f_openCommonPopUp(4, "", clntNm, 'F', 'F', rowIndex);
    }
  } catch (e) {
    console.log("gr_results_onafteredit : " + e);
  }
};
scwin.gr_manager_onafteredit = function (rowIndex, columnIndex, value) {
  try {
    let colid = gr_manager.getColumnID(columnIndex);
    if (colid == "clntNo") {
      let clntNo = gr_manager.getCellData(rowIndex, "clntNo");
      if (clntNo == "") {
        gr_manager.setCellData(rowIndex, "clntNo", "");
        return false;
      }
      scwin.f_openCommonPopUp(5, clntNo, "", 'F', 'F', rowIndex);
    }
  } catch (e) {
    console.log("gr_results_onafteredit : " + e);
  }
};
